import React, { useRef, useState, useEffect } from "react";
import Navbar from "./Navbar";
import SideNav from "./SideNav";
import Hero from "./Hero";
import Manifesto from "./Manifesto";
import HowItWorks from "./HowItWorks";
import AppPanel from "./AppPanel";
import { TechSection, Footer } from "./TechSection";
import "./global.css";

const SECTIONS = ["hero", "manifesto", "how", "tech", "app"];

export default function App() {
    const appRef   = useRef(null);
    const howRef   = useRef(null);
    const [wallet, setWallet]   = useState("");
    const [active, setActive]   = useState("hero");

    // Track active section via IntersectionObserver
    useEffect(() => {
        const observers = SECTIONS.map(id => {
            const el = document.getElementById(id);
            if (!el) return null;
            const io = new IntersectionObserver(
                ([e]) => { if (e.isIntersecting) setActive(id); },
                { threshold: 0.4 }
            );
            io.observe(el);
            return io;
        }).filter(Boolean);
        return () => observers.forEach(io => io.disconnect());
    }, []);

    const scrollToApp = () => document.getElementById("app")?.scrollIntoView({ behavior: "smooth" });
    const scrollToHow = () => document.getElementById("how")?.scrollIntoView({ behavior: "smooth" });

    return (
        <div>
            <Navbar wallet={wallet} onLaunchApp={scrollToApp} />
            <SideNav active={active} />
            <Hero onLaunchApp={scrollToApp} onHowItWorks={scrollToHow} />
            <Manifesto />
            <HowItWorks />
            <TechSection />
            <AppPanel forwardRef={appRef} onWalletChange={setWallet} />
            <Footer onLaunchApp={scrollToApp} />
        </div>
    );
}
